import java.util.*;
import java.util.stream.*;
public class StreamOpt {
    public static void main(String[] args) {
        Optional<Integer> first = Stream.of(3,1,4,1,5)
            .filter(n -> n > 3)
            .findFirst();
        System.out.println(first.isPresent());
        System.out.println(first.get());
        Optional<Integer> none = Stream.of(1,2,3)
            .filter(n -> n > 10)
            .findFirst();
        System.out.println(none.orElse(-1));
    }
}
